    civic_docs = json.load(f)
with open(var_call_wBrhbjFYhMnA5OtJjyPFnbnZ, 'r') as f:
    funding = json.load(f)

funding_df = pd.DataFrame(funding)
# Ensure Amount is int
funding_df['Amount'] = funding_df['Amount'].astype(int)

